class RsGetOrdersServiceImpl:
    def get_rs_orders(self, invoice_num=None, request_type=None):
        if invoice_num is not None and not isinstance(invoice_num, str):
            raise TypeError("invoice_num must be a string")

        if request_type not in ['type1', 'type2', None]:
            raise ValueError("Invalid request_type")

        # Simulated order retrieval logic
        orders = self._retrieve_orders(invoice_num, request_type)
        return orders

    def _retrieve_orders(self, invoice_num, request_type):
        # Simulated database of orders
        orders_db = [
            {'invoice_num': 'INV001', 'request_type': 'type1'},
            {'invoice_num': 'INV002', 'request_type': 'type2'},
            {'invoice_num': 'INV003', 'request_type': 'type1'},
        ]

        if invoice_num:
            return [order for order in orders_db if order['invoice_num'] == invoice_num]

        if request_type:
            return [order for order in orders_db if order['request_type'] == request_type]

        return orders_db

